def _utc_now_iso() -> str:
    return datetime.utcnow().replace(microsecond=0).isoformat() + "Z"

def _safe_mkdir(path: str) -> None:
    os.makedirs(path, exist_ok=True)

def _ext(name: str) -> str:
    return os.path.splitext(name)[1].lower()

def _sha256_bytes(b: bytes) -> str:
    return hashlib.sha256(b).hexdigest()

def _sha256_file(path: str, chunk_size: int = 1024 * 1024) -> str:
    h = hashlib.sha256()
    with open(path, "rb") as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            h.update(chunk)
    return h.hexdigest()

def _read_limited_upload(upload: UploadFile, max_bytes: int) -> bytes:
    data = upload.file.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise HTTPException(status_code=413, detail="Upload too large")
    return data

def _atomic_write_json(path: str, obj: Any) -> None:
    tmp = path + ".tmp"
    with open(tmp, "w", encoding="utf-8") as f:
        json.dump(obj, f, ensure_ascii=False, indent=2)
    os.replace(tmp, path)

def _load_json(path: str, default: Any) -> Any:
    if not os.path.exists(path):
        return default
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)

def _append_jsonl(path: str, record: Dict[str, Any]) -> None:
    _safe_mkdir(os.path.dirname(path))
    line = json.dumps(record, ensure_ascii=False)
    with open(path, "a", encoding="utf-8") as f:
        f.write(line + "\n")

def _iter_jsonl(path: str) -> List[Dict[str, Any]]:
    if not os.path.exists(path):
        return []
    out = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                out.append(json.loads(line))
            except Exception:
                continue
    return out

def _normalize_label(label: str) -> str:
    label = (label or "").strip()
    if not label:
        raise ValueError("Empty label")
    return label

def _save_image_bytes(image_bytes: bytes, dest_dir: str, preferred_ext: Optional[str] = None) -> Tuple[str, str]:
    if len(image_bytes) > DEFAULT_MAX_IMAGE_BYTES:
        raise HTTPException(status_code=413, detail="Image too large")

    try:
        img = Image.open(io.BytesIO(image_bytes))
        img = img.convert("RGB")
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid image")

    digest = _sha256_bytes(image_bytes)
    ext = (preferred_ext or ".jpg").lower()
    if ext not in ALLOWED_IMAGE_EXT:
        ext = ".jpg"

    rel_name = f"{digest}{ext}"
    abs_path = os.path.join(dest_dir, rel_name)
    if not os.path.exists(abs_path):
        _safe_mkdir(dest_dir)
        tmp = abs_path + ".tmp"
        img.save(tmp, format="JPEG", quality=92, optimize=True)
        os.replace(tmp, abs_path)
    return rel_name, digest

def _ensure_labels(labels: List[str]) -> Dict[str, int]:
    labels = [_normalize_label(x) for x in labels]
    existing = _load_json(LABELS_PATH, default={"label_to_index": {}, "index_to_label": []})
    label_to_index = existing.get("label_to_index", {})
    index_to_label = existing.get("index_to_label", [])

    changed = False
    for lab in labels:
        if lab not in label_to_index:
            label_to_index[lab] = len(index_to_label)
            index_to_label.append(lab)
            changed = True

    if changed:
        _atomic_write_json(LABELS_PATH, {"label_to_index": label_to_index, "index_to_label": index_to_label})

    return label_to_index

def _get_labels_mapping() -> Dict[str, Any]:
    return _load_json(LABELS_PATH, default={"label_to_index": {}, "index_to_label": []})

def _train_state_load() -> Dict[str, Any]:
    return _load_json(TRAIN_STATE_PATH, default={
        "status": "idle",
        "last_train_started_at": None,
        "last_train_finished_at": None,
        "last_train_error": None,
        "last_metrics": None,
        "last_model_path": LATEST_MODEL_PATH if os.path.exists(LATEST_MODEL_PATH) else None,
        "active_job_id": None,
    })

def _train_state_save(state: Dict[str, Any]) -> None:
    _atomic_write_json(TRAIN_STATE_PATH, state)

