def _registry_records() -> List[Dict[str, Any]]:
    recs = _iter_jsonl(REGISTRY_PATH)
    recs = [r for r in recs if r.get("type") in ("example", "csv_import")]
    return recs

def _examples_from_registry() -> pd.DataFrame:
    recs = _registry_records()
    rows = []
    for r in recs:
        if r.get("type") == "example":
            rows.append({
                "image_relpath": r.get("image_relpath"),
                "label": r.get("label"),
                "source": r.get("source", "upload"),
                "created_at": r.get("created_at"),
                "sha256": r.get("sha256"),
            })
        elif r.get("type") == "csv_import":
            items = r.get("items", [])
            for it in items:
                rows.append({
                    "image_relpath": it.get("image_relpath"),
                    "label": it.get("label"),
                    "source": r.get("source", "csv"),
                    "created_at": r.get("created_at"),
                    "sha256": it.get("sha256"),
                })
    df = pd.DataFrame(rows)
    if df.empty:
        return df
    df = df.dropna(subset=["image_relpath", "label"])
    df["label"] = df["label"].astype(str).map(lambda x: x.strip())
    df = df[df["label"].map(lambda x: len(x) > 0)]
    df["abs_path"] = df["image_relpath"].map(lambda p: os.path.join(IMAGES_DIR, p))
    df = df[df["abs_path"].map(os.path.exists)]
    df = df.drop_duplicates(subset=["sha256", "label"], keep="last")
    return df.reset_index(drop=True)

def _split_dataframe(df: pd.DataFrame, val_split: float, test_split: float, seed: int = 1337) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if df.empty:
        return df, df, df
    rng = np.random.default_rng(seed)
    idx = np.arange(len(df))
    rng.shuffle(idx)
    df = df.iloc[idx].reset_index(drop=True)

    n = len(df)
    n_test = int(round(n * test_split))
    n_val = int(round(n * val_split))
    n_test = min(max(n_test, 0), n)
    n_val = min(max(n_val, 0), n - n_test)

    df_test = df.iloc[:n_test].reset_index(drop=True)
    df_val = df.iloc[n_test:n_test + n_val].reset_index(drop=True)
    df_train = df.iloc[n_test + n_val:].reset_index(drop=True)
    return df_train, df_val, df_test

def _make_tf_dataset(df: pd.DataFrame, label_to_index: Dict[str, int], image_size: int, batch_size: int, training: bool) -> tf.data.Dataset:
    paths = df["abs_path"].astype(str).tolist()
    labels = [label_to_index[_normalize_label(l)] for l in df["label"].astype(str).tolist()]

    path_ds = tf.data.Dataset.from_tensor_slices(paths)
    label_ds = tf.data.Dataset.from_tensor_slices(tf.cast(labels, tf.int32))
    ds = tf.data.Dataset.zip((path_ds, label_ds))

    def _load(path, label):
        img_bytes = tf.io.read_file(path)
        img = tf.image.decode_image(img_bytes, channels=3, expand_animations=False)
        img = tf.image.convert_image_dtype(img, tf.float32)
        img = tf.image.resize(img, [image_size, image_size], method=tf.image.ResizeMethod.BILINEAR)
        return img, label

    ds = ds.map(_load, num_parallel_calls=tf.data.AUTOTUNE)

    if training:
        aug = keras.Sequential([
            keras.layers.RandomFlip("horizontal"),
            keras.layers.RandomRotation(0.05),
            keras.layers.RandomZoom(0.1),
            keras.layers.RandomContrast(0.1),
        ])
        def _aug(x, y):
            return aug(x, training=True), y
        ds = ds.map(_aug, num_parallel_calls=tf.data.AUTOTUNE)
        ds = ds.shuffle(min(len(paths), 4096), reshuffle_each_iteration=True)

    ds = ds.batch(batch_size).prefetch(tf.data.AUTOTUNE)
    return ds

# ----------------------------
# Model
# ----------------------------
def _build_model(num_classes: int, image_size: int, learning_rate: float) -> keras.Model:
    base = keras.applications.MobileNetV3Small(
        input_shape=(image_size, image_size, 3),
        include_top=False,
        weights="imagenet",
        pooling="avg",
    )
    base.trainable = False

    inputs = keras.Input(shape=(image_size, image_size, 3))
    x = keras.applications.mobilenet_v3.preprocess_input(inputs)
    x = base(x, training=False)
    x = keras.layers.Dropout(0.2)(x)
    outputs = keras.layers.Dense(num_classes, activation="softmax")(x)

    model = keras.Model(inputs, outputs)
    model.compile(
        optimizer=keras.optimizers.Adam(learning_rate=learning_rate),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model

def _fine_tune(model: keras.Model, learning_rate: float) -> None:
    base = None
    for layer in model.layers:
        if isinstance(layer, keras.Model) and layer.name.startswith("MobilenetV3"):
            base = layer
            break
    if base is None:
        for layer in model.layers:
            if hasattr(layer, "layers") and layer.name.lower().startswith("mobilenet"):
                base = layer
                break
    if base is None:
        return
    base.trainable = True
    model.compile(
        optimizer=keras.optimizers.Adam(learning_rate=learning_rate),
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )

# ----------------------------
# Training job management
# ----------------------------
_train_lock = threading.Lock()

def _count_examples() -> int:
    df = _examples_from_registry()
    return int(len(df))

def _train_job(job_id: str,
               image_size: int,
               batch_size: int,
               epochs: int,
               learning_rate: float,
               val_split: float,
               test_split: float,
               min_examples_to_train: int,
               fine_tune: bool,
               fine_tune_lr: float,
               fine_tune_epochs: int,
               seed: int) -> None:
    with _train_lock:
        state = _train_state_load()
        state["status"] = "training"
        state["active_job_id"] = job_id
        state["last_train_started_at"] = _utc_now_iso()
        state["last_train_finished_at"] = None
        state["last_train_error"] = None
        state["last_metrics"] = None
        _train_state_save(state)

    try:
        df = _examples_from_registry()
        if len(df) < min_examples_to_train:
            raise RuntimeError(f"Not enough examples to train: {len(df)} < {min_examples_to_train}")

        labels = sorted(df["label"].astype(str).map(_normalize_label).unique().tolist())
        label_to_index = _ensure_labels(labels)
        num_classes = len(label_to_index)
        if num_classes < 2:
            raise RuntimeError("Need at least 2 classes to train")

        df_train, df_val, df_test = _split_dataframe(df, val_split=val_split, test_split=test_split, seed=seed)
        if len(df_train) == 0 or len(df_val) == 0:
            raise RuntimeError("Insufficient data after split; adjust splits or add more data")

        train_ds = _make_tf_dataset(df_train, label_to_index, image_size, batch_size, training=True)
        val_ds = _make_tf_dataset(df_val, label_to_index, image_size, batch_size, training=False)
        test_ds = _make_tf_dataset(df_test, label_to_index, image_size, batch_size, training=False) if len(df_test) else None

        model = _build_model(num_classes=num_classes, image_size=image_size, learning_rate=learning_rate)

        ckpt_path = os.path.join(CHECKPOINT_DIR, f"{job_id}.keras")
        callbacks = [
            keras.callbacks.ModelCheckpoint(ckpt_path, monitor="val_accuracy", save_best_only=True, save_weights_only=False),
            keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=3, restore_best_weights=True),
        ]

        history = model.fit(train_ds, validation_data=val_ds, epochs=epochs, callbacks=callbacks, verbose=1)

        if fine_tune:
            _fine_tune(model, learning_rate=fine_tune_lr)
            ft_callbacks = [
                keras.callbacks.EarlyStopping(monitor="val_accuracy", patience=2, restore_best_weights=True),
            ]
            ft_history = model.fit(train_ds, validation_data=val_ds, epochs=fine_tune_epochs, callbacks=ft_callbacks, verbose=1)
        else:
            ft_history = None

        metrics = {}
        metrics["train"] = {k: [float(x) for x in v] for k, v in history.history.items()}
        if ft_history is not None:
            metrics["fine_tune"] = {k: [float(x) for x in v] for k, v in ft_history.history.items()}

        if test_ds is not None:
            test_loss, test_acc = model.evaluate(test_ds, verbose=0)
            metrics["test_loss"] = float(test_loss)
            metrics["test_accuracy"] = float(test_acc)

        export_path = os.path.join(EXPORT_DIR, f"{job_id}.keras")
        model.save(export_path)
        shutil.copyfile(export_path, LATEST_MODEL_PATH)

        state = _train_state_load()
        state["status"] = "idle"
        state["active_job_id"] = None
        state["last_train_finished_at"] = _utc_now_iso()
        state["last_train_error"] = None
        state["last_metrics"] = metrics
        state["last_model_path"] = LATEST_MODEL_PATH
        _train_state_save(state)

        _append_jsonl(REGISTRY_PATH, {
            "type": "train_run",
            "job_id": job_id,
            "created_at": _utc_now_iso(),
            "num_examples": int(len(df)),
            "num_classes": int(num_classes),
            "image_size": int(image_size),
            "batch_size": int(batch_size),
            "epochs": int(epochs),
            "learning_rate": float(learning_rate),
            "fine_tune": bool(fine_tune),
            "fine_tune_lr": float(fine_tune_lr),
            "fine_tune_epochs": int(fine_tune_epochs),
            "val_split": float(val_split),
            "test_split": float(test_split),
            "seed": int(seed),
            "export_path": export_path,
        })

    except Exception as e:
        state = _train_state_load()
        state["status"] = "error"
        state["active_job_id"] = None
        state["last_train_finished_at"] = _utc_now_iso()
        state["last_train_error"] = str(e)
        _train_state_save(state)

