app = FastAPI(title="Community-Driven AI Training Pipeline", version="1.0.0")

class PredictResponse(BaseModel):
    label: str
    confidence: float
    top_k: List[Dict[str, float]]

class TrainRequest(BaseModel):
    image_size: int = DEFAULT_IMAGE_SIZE
    batch_size: int = DEFAULT_BATCH_SIZE
    epochs: int = DEFAULT_EPOCHS
    learning_rate: float = DEFAULT_LEARNING_RATE
    val_split: float = DEFAULT_VAL_SPLIT
    test_split: float = DEFAULT_TEST_SPLIT
    min_examples_to_train: int = DEFAULT_MIN_EXAMPLES_TO_TRAIN
    fine_tune: bool = True
    fine_tune_lr: float = 1e-5
    fine_tune_epochs: int = 2
    seed: int = 1337

def _load_latest_model() -> Optional[keras.Model]:
    if not os.path.exists(LATEST_MODEL_PATH):
        return None
    try:
        return keras.models.load_model(LATEST_MODEL_PATH)
    except Exception:
        return None

def _prepare_image_for_infer(image_bytes: bytes, image_size: int) -> np.ndarray:
    img = Image.open(io.BytesIO(image_bytes)).convert("RGB")
    img = img.resize((image_size, image_size))
    arr = np.asarray(img).astype(np.float32)
    arr = np.expand_dims(arr, axis=0)
    return arr

@app.get("/health")
def health():
    state = _train_state_load()
    labels = _get_labels_mapping()
    return {
        "status": "ok",
        "train_status": state.get("status"),
        "active_job_id": state.get("active_job_id"),
        "num_examples": _count_examples(),
        "num_labels": len(labels.get("index_to_label", [])),
        "has_model": os.path.exists(LATEST_MODEL_PATH),
        "latest_model_path": state.get("last_model_path"),
        "time": _utc_now_iso(),
    }

@app.get("/labels")
def labels():
    return _get_labels_mapping()

@app.get("/train/status")
def train_status():
    return _train_state_load()

@app.post("/upload/example")
async def upload_example(
    image: UploadFile = File(...),
    label: str = Form(...),
    source: str = Form("upload"),
):
    label = _normalize_label(label)
    if _ext(image.filename or "") not in ALLOWED_IMAGE_EXT:
        raise HTTPException(status_code=400, detail="Unsupported image type")

    image_bytes = _read_limited_upload(image, DEFAULT_MAX_IMAGE_BYTES)
    rel_name, digest = _save_image_bytes(image_bytes, IMAGES_DIR, preferred_ext=_ext(image.filename or ".jpg"))
    _ensure_labels([label])

    record = {
        "type": "example",
        "id": str(uuid.uuid4()),
        "created_at": _utc_now_iso(),
        "source": source,
        "label": label,
        "image_relpath": rel_name,
        "sha256": digest,
        "original_filename": image.filename,
    }
    _append_jsonl(REGISTRY_PATH, record)

    return {
        "ok": True,
        "id": record["id"],
        "label": label,
        "image_relpath": rel_name,
        "sha256": digest,
        "num_examples": _count_examples(),
    }

@app.post("/upload/csv")
async def upload_csv(
    csv_file: UploadFile = File(...),
    source: str = Form("csv"),
    image_column: str = Form("image"),
    label_column: str = Form("label"),
    image_base_url: Optional[str] = Form(None),
):
    if _ext(csv_file.filename or "") not in ALLOWED_CSV_EXT:
        raise HTTPException(status_code=400, detail="Unsupported CSV type")

    csv_bytes = _read_limited_upload(csv_file, DEFAULT_MAX_UPLOAD_BYTES)
    upload_id = str(uuid.uuid4())
    upload_dir = os.path.join(UPLOADS_DIR, upload_id)
    _safe_mkdir(upload_dir)
    csv_path = os.path.join(upload_dir, "data.csv")
    with open(csv_path, "wb") as f:
        f.write(csv_bytes)

    try:
        df = pd.read_csv(csv_path)
    except Exception:
        raise HTTPException(status_code=400, detail="Invalid CSV")

    if len(df) > DEFAULT_MAX_CSV_ROWS:
        raise HTTPException(status_code=400, detail="CSV too large")

    if image_column not in df.columns or label_column not in df.columns:
        raise HTTPException(status_code=400, detail=f"CSV must contain columns: {image_column}, {label_column}")

    items = []
    labels_to_add = []

    for i, row in df.iterrows():
        img_ref = row.get(image_column)
        lab = row.get(label_column)
        if pd.isna(img_ref) or pd.isna(lab):
            continue
        lab = _normalize_label(str(lab))
        img_ref = str(img_ref).strip()
        if not img_ref:
            continue

        if img_ref.startswith("http://") or img_ref.startswith("https://"):
            continue

        if image_base_url and (img_ref.startswith("/") or ("://" not in img_ref and not os.path.isabs(img_ref))):
            continue

        abs_img = img_ref if os.path.isabs(img_ref) else os.path.join(upload_dir, img_ref)
        if not os.path.exists(abs_img):
            continue

        if _ext(abs_img) not in ALLOWED_IMAGE_EXT:
            continue

        try:
            with open(abs_img, "rb") as f:
                b = f.read(DEFAULT_MAX_IMAGE_BYTES + 1)
            if len(b) > DEFAULT_MAX_IMAGE_BYTES:
                continue
            rel_name, digest = _save_image_bytes(b, IMAGES_DIR, preferred_ext=_ext(abs_img))
        except Exception:
            continue

        items.append({
            "image_relpath": rel_name,
            "label": lab,
            "sha256": digest,
            "row_index": int(i),
        })
        labels_to_add.append(lab)

    if not items:
        raise HTTPException(status_code=400, detail="No valid local images found in CSV import")

    _ensure_labels(labels_to_add)

    record = {
        "type": "csv_import",
        "id": upload_id,
        "created_at": _utc_now_iso(),
        "source": source,
        "original_filename": csv_file.filename,
        "image_column": image_column,
        "label_column": label_column,
        "items_count": len(items),
        "items": items,
    }
    _append_jsonl(REGISTRY_PATH, record)

    return {
        "ok": True,
        "id": upload_id,
        "items_count": len(items),
        "num_examples": _count_examples(),
    }

@app.post("/train")
def train(req: TrainRequest, background_tasks: BackgroundTasks):
    state = _train_state_load()
    if state.get("status") == "training":
        raise HTTPException(status_code=409, detail="Training already in progress")

    job_id = str(uuid.uuid4())
    background_tasks.add_task(
        _train_job,
        job_id,
        int(req.image_size),
        int(req.batch_size),
        int(req.epochs),
        float(req.learning_rate),
        float(req.val_split),
        float(req.test_split),
        int(req.min_examples_to_train),
        bool(req.fine_tune),
        float(req.fine_tune_lr),
        int(req.fine_tune_epochs),
        int(req.seed),
    )
    state["status"] = "queued"
    state["active_job_id"] = job_id
    state["last_train_error"] = None
    _train_state_save(state)

    return {"ok": True, "job_id": job_id, "status": "queued"}

@app.post("/predict", response_model=PredictResponse)
async def predict(image: UploadFile = File(...), top_k: int = Form(5)):
    if _ext(image.filename or "") not in ALLOWED_IMAGE_EXT:
        raise HTTPException(status_code=400, detail="Unsupported image type")

    model = _load_latest_model()
    if model is None:
        raise HTTPException(status_code=404, detail="No trained model available")

    labels = _get_labels_mapping().get("index_to_label", [])
    if not labels:
        raise HTTPException(status_code=500, detail="Labels mapping missing")

    image_bytes = _read_limited_upload(image, DEFAULT_MAX_IMAGE_BYTES)
    image_size = int(model.input_shape[1])
    x = _prepare_image_for_infer(image_bytes, image_size=image_size)

    preds = model.predict(x, verbose=0)[0]
    preds = np.asarray(preds, dtype=np.float32)
    k = int(max(1, min(top_k, len(preds))))
    idx = np.argsort(-preds)[:k]
    top = [{"label": labels[int(i)], "confidence": float(preds[int(i)])} for i in idx]
    best = top[0]
    return PredictResponse(label=best["label"], confidence=best["confidence"], top_k=top)

@app.get("/dataset/stats")
def dataset_stats():
    df = _examples_from_registry()
    labels = df["label"].astype(str).map(lambda x: x.strip()).tolist() if not df.empty else []
    counts = {}
    for l in labels:
        counts[l] = counts.get(l, 0) + 1
    counts_sorted = dict(sorted(counts.items(), key=lambda kv: (-kv[1], kv[0])))
    return {
        "num_examples": int(len(df)),
        "num_classes": int(len(counts_sorted)),
        "class_counts": counts_sorted,
        "time": _utc_now_iso(),
    }

@app.delete("/dataset/reset")
def dataset_reset(confirm: str):
    if confirm != "DELETE_ALL_DATA":
        raise HTTPException(status_code=400, detail="Set confirm=DELETE_ALL_DATA to proceed")
    if os.path.exists(DATA_DIR):
        shutil.rmtree(DATA_DIR)
    _safe_mkdir(DATA_DIR)
    _safe_mkdir(UPLOADS_DIR)
    _safe_mkdir(IMAGES_DIR)
    _safe_mkdir(CHECKPOINT_DIR)
    _safe_mkdir(EXPORT_DIR)
    if os.path.exists(TRAIN_STATE_PATH):
        os.remove(TRAIN_STATE_PATH)
    if os.path.exists(LABELS_PATH):
        os.remove(LABELS_PATH)
    return {"ok": True}

